+	sub_get_image = it.subscribe("/robot_core/camera/rgb/image_color", 1, &PhotoApp::savePhoto, this);
+	sub_get_depth_image = it.subscribe("/robot_core/camera/depth/image", 1, &PhotoApp::findNearestPoint, this);
