+	cmd_vel.linear.y = 0.0f;
+	cmd_vel.linear.z = 0.0f;
+	cmd_vel.angular.x = 0.0f;
+	cmd_vel.angular.y = 0.0f;
+	cmd_vel.angular.z = 0.0f; 
